var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"마차가 멈췄어요. 수도원에 도착했나 봐요.","JPN":"馬車が止まりました。修道院に着いたようですね。","ENG":"The carriage stopped! We must've arrived at the monastery!","TWN":"馬車停了。好像到修道院了。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럴까요? 여기가 수도원이면 저희더러 내리라고 한마디 할 만도 한데.","JPN":"そうなのでしょうか？　ここが修道院なら、私たちに降りろと一言いうはずですわ。","ENG":"Perhaps. But if this were the monastery, the driver would have told us that, no?","TWN":"是嗎？可如果這裡是修道院的話，應該會讓我們下車才對。"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"혹시라도 인신매매 같은 범죄에 연루되진 않았겠죠?","JPN":"まさか人身売買のような犯罪に巻き込まれたのでは？","ENG":"What if we are caught in the middle of a human trafficking crime?","TWN":"我們不會被牽扯進拐賣人口的犯罪吧？"},"stage":{"bg":"BLACK","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"뭘 궁시렁거리고 있어. 그냥 내려서 확인하면 될 것 가지고.","JPN":"何をぶつぶつ言ってんだよ。降りて確認したらいいじゃん。","ENG":"What are you muttering about? Just step out and check.","TWN":"在嘀嘀咕咕什麼，直接下去看看不就行了。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응? 여기가 수도원이 있는 영지야, 부학회장?","JPN":"うん？　ここが修道院がある領地なの？　副学会長。","ENG":"Hmm? Are you sure this is the right place, Vice President?","TWN":"嗯？這裡是修道院所在的領地嗎，副學會長？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그걸 저한테 물어 보는 건가요. 길을 안다고 한 사람은 당신이잖아요.","JPN":"それを私に聞くのですか？　道を知っていると言ったのはあなたでしょう？","ENG":"Why are you asking me? You said you knew how to get there.","TWN":"你是在問我嗎？說認識路的人不是你嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"운전사 분도 안 보이세요. 다른 외지인에게 살해당하시진 않았겠죠?","JPN":"運転手さんも見当たりませんね。まさか、他の者に殺されたなんてことないですよね？","ENG":"The driver's gone missing too. We're not going to get murdered by another outlander, are we?","TWN":"司機也不見了呢。不會是被別的外地人殺了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음…….","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"사장님, 뭔가 짚이는 게 있나요?","JPN":"社長、何か心当たりでも？","ENG":"Is there something on your mind, Boss?","TWN":"老闆，你猜到什麼了嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"나보다는 맥크레디 양 자네가 잘 알 것 같네만.","JPN":"私よりマクレディー君、君が知っているんじゃないか？","ENG":"I think you'll know better than I will, Regina.","TWN":"麥克蕾蒂，你好像應該比我更清楚吧。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"학회의 영지에 대해서라면 부학회장이 더 박식하겠지.","JPN":"学会の領地に関することなら副学会長の方がよく知っているはずだ。","ENG":"The Society's Vice President should be more knowledgeable about its estate.","TWN":"關於學會的領地，副學會長應該更了解才對。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"영지요? 그거라면…….","JPN":"領地ですか？　それなら……","ENG":"Estate? If you are talking abou–","TWN":"領地嗎？那樣的話……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러고 보니, 저택 지하에 보관된 자료들을 검토하면서 본 기억이 있어요.","JPN":"そういえば、邸宅の地下に保管されている資料を検討した時に見た記憶がありますわ。","ENG":"Come to think of it, I do remember reviewing records stored in the mansion's basement.","TWN":"你這麼一說我想起來了，我記得我在研究宅邸地下保管的資料時看到過。"},"stage":{"bg":"ESPR2_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떤 측면에서는…… 네. 인정하고 말았죠.","JPN":"ある側面では……はい。認めてしまいました。","ENG":"In some respects... Yes. I did admit it.","TWN":"在某些方面……嗯，我得承認。"},"stage":{"bg":"ESPR2_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가문의 선조들께서 집착했던 미신과 병적인 연구에 일말의 성과들도 있었다는 걸요.","JPN":"マクレディー家の先祖が執着していた迷信と病的な研究に、それなりの成果もあったということを。","ENG":"That my family's obsession with superstitions and horrific research had yielded results.","TWN":"家族的先祖們執著的迷信和病態研究，也取得了一些成果。"},"stage":{"bg":"ESPR2_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>침식 현상은 인간의 본능에 각인된 감정을 투영한다.</color>","JPN":"<color=#ffd34c>侵食現象は人間の本能に刻印された感情を投影する。</color>","ENG":"<color=#ffd34c>Counterside Effect reflects the emotions engraved in human instinct.</color>","TWN":"<color=#ffd34c>侵蝕現象會投射刻印在人類本能中的感情。</color>"},"stage":{"bg":"ESPR2_06","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>침식 현상은 침식파가 유입되어 발생한다.</color>","JPN":"<color=#ffd34c>侵食現象は侵食波が流入して発生する。</color>","ENG":"<color=#ffd34c>Counterside Effect is caused by an influx of Corruption ray.</color>","TWN":"<color=#ffd34c>侵蝕現象是由侵蝕波的流入引起的。</color>"},"stage":{"bg":"ESPR2_06","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};